ALGORITHM PlayfairCipher
INPUT: keyword, plaintext (for encryption) OR ciphertext (for decryption)
OUTPUT: ciphertext (for encryption) OR plaintext (for decryption)

// ============================================
// STEP 1: CONSTRUCT PLAYFAIR MATRIX
// ============================================
FUNCTION CreatePlayfairMatrix(keyword):
 matrix ← 5x5 array
 alphabet ← "ABCDEFGHIKLMNOPQRSTUVWXYZ" // I and J combined

 // Remove duplicate letters from keyword
 cleanedKey ← ""
 FOR each letter in keyword:
 IF letter NOT IN cleanedKey AND letter != 'J':
 cleanedKey ← cleanedKey + letter

 // Fill matrix with keyword letters first
 filled ← ""
 filled ← cleanedKey

 // Add remaining alphabet letters
 FOR each letter in alphabet:
 IF letter NOT IN filled:
 filled ← filled + letter

 // Fill 5x5 matrix row by row
 index ← 0
 FOR row FROM 0 TO 4:
 FOR col FROM 0 TO 4:
 matrix[row][col] ← filled[index]
 index ← index + 1

 RETURN matrix

// ============================================
// STEP 2: PREPARE PLAINTEXT
// ============================================
FUNCTION PreparePlaintext(plaintext):
 // Remove spaces and convert to uppercase
 text ← RemoveSpaces(plaintext)
 text ← UpperCase(text)

 // Replace J with I
 text ← ReplaceAll(text, 'J', 'I')

 // Split into pairs
 pairs ← ""
 i ← 0
 WHILE i < length(text):
 IF i+1 < length(text) AND text[i] == text[i+1]:
 // Double letter: insert X between them
 pairs ← pairs + text[i] + 'X'
 i ← i + 1
 ELSE:
 pairs ← pairs + text[i]
 i ← i + 1

 // Pad with X if odd length
 IF length(pairs) MOD 2 != 0:
 pairs ← pairs + 'X'

 RETURN pairs

// ============================================
// STEP 3: FIND LETTER POSITION IN MATRIX
// ============================================
FUNCTION FindPosition(matrix, letter):
 FOR row FROM 0 TO 4:
 FOR col FROM 0 TO 4:
 IF matrix[row][col] == letter:
 RETURN (row, col)
 RETURN (-1, -1) // Not found

// ============================================
// STEP 4: ENCRYPTION RULES
// ============================================
FUNCTION EncryptDigraph(matrix, a, b):
 posA ← FindPosition(matrix, a)
 posB ← FindPosition(matrix, b)
 rowA ← posA.row, colA ← posA.col
 rowB ← posB.row, colB ← posB.col

 IF rowA == rowB:
 // RULE 1: Same row - shift right (wrap around)
 colA ← (colA + 1) MOD 5
 colB ← (colB + 1) MOD 5
 ELSE IF colA == colB:
 // RULE 2: Same column - shift down (wrap around)
 rowA ← (rowA + 1) MOD 5
 rowB ← (rowB + 1) MOD 5
 ELSE:
 // RULE 3: Rectangle - swap columns
 temp ← colA
 colA ← colB
 colB ← temp

 RETURN matrix[rowA][colA] + matrix[rowB][colB]

// ============================================
// STEP 5: DECRYPTION RULES
// ============================================
FUNCTION DecryptDigraph(matrix, a, b):
 posA ← FindPosition(matrix, a)
 posB ← FindPosition(matrix, b)
 rowA ← posA.row, colA ← posA.col
 rowB ← posB.row, colB ← posB.col

 IF rowA == rowB:
 // RULE 1: Same row - shift left (wrap around)
 colA ← (colA - 1 + 5) MOD 5
 colB ← (colB - 1 + 5) MOD 5
 ELSE IF colA == colB:
 // RULE 2: Same column - shift up (wrap around)
 rowA ← (rowA - 1 + 5) MOD 5
 rowB ← (rowB - 1 + 5) MOD 5
 ELSE:
 // RULE 3: Rectangle - swap columns (same as encryption)
 temp ← colA
 colA ← colB
 colB ← temp

 RETURN matrix[rowA][colA] + matrix[rowB][colB]

// ============================================
// MAIN ENCRYPTION FUNCTION
// ============================================
FUNCTION Encrypt(keyword, plaintext):
 matrix ← CreatePlayfairMatrix(keyword)
 preparedText ← PreparePlaintext(plaintext)

 ciphertext ← ""
 FOR i FROM 0 TO length(preparedText) STEP 2:
 a ← preparedText[i]
 b ← preparedText[i+1]
 cipherPair ← EncryptDigraph(matrix, a, b)
 ciphertext ← ciphertext + cipherPair

 RETURN ciphertext

// ============================================
// MAIN DECRYPTION FUNCTION
// ============================================
FUNCTION Decrypt(keyword, ciphertext):
 matrix ← CreatePlayfairMatrix(keyword)
 ciphertext ← UpperCase(ciphertext)
 ciphertext ← ReplaceAll(ciphertext, 'J', 'I')

 plaintext ← ""
 FOR i FROM 0 TO length(ciphertext) STEP 2:
 a ← ciphertext[i]
 b ← ciphertext[i+1]
 plainPair ← DecryptDigraph(matrix, a, b)
 plaintext ← plaintext + plainPair

 RETURN plaintext

// ============================================
// EXAMPLE USAGE
// ============================================
// keyword ← "MONARCHY"
// plaintext ← "HIDE GOLD"
// encrypted ← Encrypt(keyword, plaintext)
// decrypted ← Decrypt(keyword, encrypted)

#include <stdio.h>
#include <string.h>
#include <ctype.h>

#define MATRIX_SIZE 5
#define ALPHABET_SIZE 25

// Global matrix
char matrix[MATRIX_SIZE][MATRIX_SIZE];

/**
 * Create the 5x5 Playfair matrix from a keyword
 * Combines I and J into a single position
 */
void createMatrix(const char *keyword) {
 int keyLen = strlen(keyword);
 char cleanedKey[26] = {0};
 int keyIndex = 0;

 // Clean keyword: remove duplicates and handle I/J
 for (int i = 0; i < keyLen; i++) {
 char c = toupper(keyword[i]);
 if (c == 'J') c = 'I'; // Combine I and J

 // Check if character already in cleanedKey
 int found = 0;
 for (int j = 0; j < keyIndex; j++) {
 if (cleanedKey[j] == c) {
 found = 1;
 break;
 }
 }
 if (!found && isalpha(c)) {
 cleanedKey[keyIndex++] = c;
 }
 }

 // Create alphabet string (I/J combined, so 25 letters)
 const char *alphabet = "ABCDEFGHIKLMNOPQRSTUVWXYZ";

 // Fill matrix with keyword first, then remaining alphabet
 char matrixChars[26];
 int mIndex = 0;

 // Add keyword letters
 for (int i = 0; i < keyIndex; i++) {
 matrixChars[mIndex++] = cleanedKey[i];
 }

 // Add remaining alphabet letters
 for (int i = 0; i < ALPHABET_SIZE; i++) {
 int found = 0;
 for (int j = 0; j < mIndex; j++) {
 if (matrixChars[j] == alphabet[i]) {
 found = 1;
 break;
 }
 }
 if (!found) {
 matrixChars[mIndex++] = alphabet[i];
 }
 }

 // Fill the 5x5 matrix
 for (int i = 0; i < MATRIX_SIZE; i++) {
 for (int j = 0; j < MATRIX_SIZE; j++) {
 matrix[i][j] = matrixChars[i * MATRIX_SIZE + j];
 }
 }
}

/**
 * Find position of a letter in the matrix
 */
void findPosition(char letter, int *row, int *col) {
 for (int i = 0; i < MATRIX_SIZE; i++) {
 for (int j = 0; j < MATRIX_SIZE; j++) {
 if (matrix[i][j] == letter) {
 *row = i;
 *col = j;
 return;
 }
 }
 }
 *row = -1;
 *col = -1;
}

/**
 * Prepare plaintext for encryption:
 * - Convert to uppercase
 * - Replace J with I
 * - Insert X between double letters
 * - Pad with X if odd length
 */
void preparePlaintext(const char *input, char *output) {
 int inLen = strlen(input);
 int outIndex = 0;

 for (int i = 0; i < inLen; i++) {
 char c = toupper(input[i]);
 if (c == ' ') continue; // Skip spaces
 if (c == 'J') c = 'I'; // Combine I and J

 output[outIndex++] = c;

 // Insert X between double letters
 if (i + 1 < inLen && c == toupper(input[i + 1]) && input[i + 1] != ' ') {
 output[outIndex++] = 'X';
 }
 }

 // Pad with X if odd length
 if (outIndex % 2 != 0) {
 output[outIndex++] = 'X';
 }

 output[outIndex] = '\0';
}

/**
 * Encrypt a digraph (pair of letters)
 */
void encryptDigraph(char a, char b, char *result) {
 int rowA, colA, rowB, colB;

 findPosition(a, &rowA, &colA);
 findPosition(b, &rowB, &colB);

 if (rowA == rowB) {
 // Rule 1: Same row - shift right (wrap around)
 colA = (colA + 1) % MATRIX_SIZE;
 colB = (colB + 1) % MATRIX_SIZE;
 } else if (colA == colB) {
 // Rule 2: Same column - shift down (wrap around)
 rowA = (rowA + 1) % MATRIX_SIZE;
 rowB = (rowB + 1) % MATRIX_SIZE;
 } else {
 // Rule 3: Rectangle - swap columns (opposite corners)
 int temp = colA;
 colA = colB;
 colB = temp;
 }

 result[0] = matrix[rowA][colA];
 result[1] = matrix[rowB][colB];
 result[2] = '\0';
}

/**
 * Decrypt a digraph (pair of letters)
 */
void decryptDigraph(char a, char b, char *result) {
 int rowA, colA, rowB, colB;

 findPosition(a, &rowA, &colA);
 findPosition(b, &rowB, &colB);

 if (rowA == rowB) {
 // Rule 1: Same row - shift left (wrap around)
 colA = (colA - 1 + MATRIX_SIZE) % MATRIX_SIZE;
 colB = (colB - 1 + MATRIX_SIZE) % MATRIX_SIZE;
 } else if (colA == colB) {
 // Rule 2: Same column - shift up (wrap around)
 rowA = (rowA - 1 + MATRIX_SIZE) % MATRIX_SIZE;
 rowB = (rowB - 1 + MATRIX_SIZE) % MATRIX_SIZE;
 } else {
 // Rule 3: Rectangle - swap columns (same as encryption)
 int temp = colA;
 colA = colB;
 colB = temp;
 }

 result[0] = matrix[rowA][colA];
 result[1] = matrix[rowB][colB];
 result[2] = '\0';
}

/**
 * Encrypt plaintext
 */
void encrypt(const char *keyword, const char *plaintext, char *ciphertext) {
 createMatrix(keyword);

 char prepared[256];
 preparePlaintext(plaintext, prepared);

 int len = strlen(prepared);
 int outIndex = 0;

 for (int i = 0; i < len; i += 2) {
 char result[3];
 encryptDigraph(prepared[i], prepared[i + 1], result);
 ciphertext[outIndex++] = result[0];
 ciphertext[outIndex++] = result[1];
 }
 ciphertext[outIndex] = '\0';
}

/**
 * Decrypt ciphertext
 */
void decrypt(const char *keyword, const char *ciphertext, char *plaintext) {
 createMatrix(keyword);

 // Preprocess ciphertext
 char clean[256];
 int cleanIndex = 0;
 for (int i = 0; i < strlen(ciphertext); i++) {
 char c = toupper(ciphertext[i]);
 if (c == ' ') continue;
 if (c == 'J') c = 'I';
 clean[cleanIndex++] = c;
 }
 clean[cleanIndex] = '\0';

 int len = strlen(clean);
 int outIndex = 0;

 for (int i = 0; i < len; i += 2) {
 char result[3];
 decryptDigraph(clean[i], clean[i + 1], result);
 plaintext[outIndex++] = result[0];
 plaintext[outIndex++] = result[1];
 }
 plaintext[outIndex] = '\0';
}

/**
 * Print the matrix
 */
void printMatrix() {
 printf("\nPlayfair Matrix:\n");
 printf("+-----+-----+-----+-----+-----+\n");
 for (int i = 0; i < MATRIX_SIZE; i++) {
 printf("| %c | %c | %c | %c | %c |\n",
 matrix[i][0], matrix[i][1], matrix[i][2], matrix[i][3], matrix[i][4]);
 printf("+-----+-----+-----+-----+-----+\n");
 }
}

/**
 * Main function demonstrating Playfair cipher
 */
int main() {
 const char *keyword = "MONARCHY";
 const char *plaintext = "HIDE GOLD";
 char ciphertext[256];
 char decrypted[256];

 printf("=========================================\n");
 printf(" PLAYFAIR CIPHER - C IMPLEMENTATION\n");
 printf("=========================================\n");

 // Create and display matrix
 createMatrix(keyword);
 printf("Keyword: %s\n", keyword);
 printf("Plaintext: %s\n", plaintext);
 printMatrix();

 // Prepare plaintext
 char prepared[256];
 preparePlaintext(plaintext, prepared);
 printf("\nPrepared text: %s\n", prepared);

 // Encrypt
 encrypt(keyword, plaintext, ciphertext);
 printf("Ciphertext: %s\n", ciphertext);

 // Decrypt
 decrypt(keyword, ciphertext, decrypted);
 printf("Decrypted: %s\n", decrypted);

 printf("\n=========================================\n");
 printf(" Example 2: Double Letter Handling\n");
 printf("=========================================\n");

 const char *keyword2 = "CIPHER";
 const char *plaintext2 = "BALLOON";

 createMatrix(keyword2);
 printf("\nKeyword: %s\n", keyword2);
 printf("Plaintext: %s\n", plaintext2);
 printMatrix();

 char prepared2[256];
 preparePlaintext(plaintext2, prepared2);
 printf("\nPrepared text: %s\n", prepared2);

 char ciphertext2[256];
 encrypt(keyword2, plaintext2, ciphertext2);
 printf("Ciphertext: %s\n", ciphertext2);

 char decrypted2[256];
 decrypt(keyword2, ciphertext2, decrypted2);
 printf("Decrypted: %s\n", decrypted2);

 return 0;
}
